sql:
SELECT SUM(quantity) AS total_traded
FROM trading_logs
WHERE user_id = 0;

SELECT SUM(quantity) AS total_quantity_traded
  FROM trading_logs
  WHERE user_id = 0;

SELECT MAX(trade_date) AS most_recent_trade_date
FROM trading_logs
WHERE user_id = 0;

